mapper.select:
SELECT * FROM( SELECT A.INTRFC_ID AS intrfcId ,A.SR_TYPE_CD AS srTypeCd ,A.SR_SEQ AS srSeq ,A.SYS_CD AS sysCd ,B.SYS_NM AS sysNm ,A.TRX_CD AS trxCd ,A.FILE_PATH AS filePath ,A.CRG_MAN_NM AS crgManNm ,@rownum := @rownum + 1 AS rn ,ROW_NUMBER() over (order by A.INTRFC_ID, A.SR_TYPE_CD, A.SR_SEQ, A.SYS_CD) as rn FROM TBINTRFCSRSYSDT A inner join TBSRSYSBS B on A.SYS_CD = B.SYS_CD WHERE 1=1
AND A.INTRFC_ID = #{intrfcId, jdbcType = VARCHAR}
AND A.SR_TYPE_CD = #{srTypeCd, jdbcType = VARCHAR}
AND A.SR_SEQ = #{srSeq, jdbcType = NUMERIC}
AND A.SYS_CD = #{sysCd, jdbcType = VARCHAR}
AND A.TRX_CD like CONCAT('%',#{trxCd, jdbcType = VARCHAR},'%')
AND A.FILE_PATH like CONCAT('%',#{filePath, jdbcType = VARCHAR},'%')
AND A.CRG_MAN_NM like CONCAT('%',#{crgManNm, jdbcType = VARCHAR},'%')
order by A.INTRFC_ID, A.SR_TYPE_CD, A.SR_SEQ, A.SYS_CD ) p, (SELECT @rownum := 0) r WHERE p.rn > ((#{pageNumber , jdbcType=NUMERIC}-1) * #{pageSize , jdbcType=NUMERIC}) AND p.rn <= ((#{pageNumber , jdbcType=NUMERIC} * #{pageSize, jdbcType=NUMERIC}))

		SELECT
			count(*) cnt
		FROM 
			TBINTRFCSRSYSDT
		WHERE 1=1
	
		AND A.INTRFC_ID = #{intrfcId, jdbcType = VARCHAR}
 	
	
		AND A.SR_TYPE_CD = #{srTypeCd, jdbcType = VARCHAR}
 	
	
		AND A.SR_SEQ = #{srSeq, jdbcType = NUMERIC}
 	
	
		AND A.SYS_CD = #{sysCd, jdbcType = VARCHAR}
 	
 	
		AND A.TRX_CD like CONCAT('%',#{trxCd, jdbcType = VARCHAR},'%')
 	
	
		AND A.FILE_PATH like CONCAT('%',#{filePath, jdbcType = VARCHAR},'%')
 	
 	
		AND A.CRG_MAN_NM like CONCAT('%',#{crgManNm, jdbcType = VARCHAR},'%')

