 		,#{srTypeCd, jdbcType = VARCHAR}
 		,#{srSeq, jdbcType = NUMERIC}
 		,#{sysCd, jdbcType = VARCHAR}
 		,#{trxCd, jdbcType = VARCHAR}
 		,#{filePath, jdbcType = VARCHAR}
